{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "C1=CC(=CC=C1O)O"
    ],
    "product_smiles": [
      "CC(=O)C1=CC(=C(C=C1)O)O"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This reaction shows the acylation of a simple, electron-rich aromatic compound (resorcinol) with a simple nitrile (acetonitrile) to form an aryl ketone. This is the classic textbook example of the Houben-Hoesch reaction, which is essentially a variant of the Friedel-Crafts acylation using a nitrile and a Lewis acid catalyst (like ZnCl2) with HCl. The product is 2,4-dihydroxyacetophenone.",
    "collision_avoidance_note": "The use of a nitrile as the acylating agent and an electron-rich phenol as the substrate is characteristic of the Houben-Hoesch reaction, distinguishing it from standard Friedel-Crafts acylations (which use acyl halides or anhydrides) and the Gattermann reaction (which uses HCN or its derivatives to form an aldehyde)."
  }
}
